import json
import os
from datetime import datetime
from typing import Dict, List, Any, Optional, Union


class MetaMetaClass:
    """
    Générateur de fichiers Python à partir de définitions JSON.

    Cette classe lit un fichier JSON de définitions et produit dynamiquement
    des fichiers de classe Python pour chaque objet défini.
