        with open(json_path, 'r', encoding='utf-8') as f:
            self.definitions = json.load(f)

        if labels_map_path:
            with open(labels_map_path, 'r', encoding='utf-8') as f:
                self.labels_map = json.load(f)

    def generate_metaclass_code(self, meta_class_def: Dict[str, Any]) -> str:
        today = datetime.now().strftime("%Y-%m-%d")
        class_name = meta_class_def["name"]
        inherits_from = meta_class_def.get("inherits_from", "Object")
        metas = meta_class_def.get("metas", [])
        methods = meta_class_def.get("methods", [])

        type_id = self.labels_map.get(class_name, "")

        code = f"""# Generated by MetaMetaClass
# :type: {class_name}
# :name: {class_name.lower()}.py
# :author: laNostr'AI
# :version: 1.0.0
# :created_at: {today}
# :description: Classe représentant un {class_name.lower()} dans le système
# :file_metas: {json.dumps(metas)}

from {inherits_from.lower()} import {inherits_from}

class {class_name}({inherits_from}):
    TYPE_NAME = "{class_name}"

    def __init__(self, object_id=None):
        """
        Initialise un nouvel objet {class_name}.

        Args:
            object_id: ID de l'objet dans la base de données (None pour un nouvel objet)
        """
        super().__init__(object_id=object_id, type_name=self.TYPE_NAME)
"""
        for method_name in methods:
            method_code = self._generate_method_code(method_name, class_name)
            code += f"\n{method_code}\n"

        return code

    def _generate_method_code(self, method_name: str, class_name: str) -> str:
        method_code = f"""    def {method_name}(self):
        """
        {method_name.replace('_', ' ').capitalize()} pour l'objet {class_name}.

        Returns:
            Dict[str, Any]: Résultat de l'opération
        """
        # TODO: Implémenter la méthode {method_name}
        return {{"status": "success", "message": "Méthode {method_name} exécutée"}}"""
        return method_code

