        should_close = False
        if db_connection is None:
            db_connection = sqlite3.connect("database.db")
            should_close = True
        cursor = db_connection.cursor()
        try:
            if self.id is None:
                cursor.execute("INSERT INTO Objects DEFAULT VALUES")
                self.id = cursor.lastrowid
                type_id = self._get_label_id(self.type_name)
