            db_connection = sqlite3.connect("database.db")
            should_close = True
        cursor = db_connection.cursor()
        try:
            value_id = self._save_value_as_label(meta_value, cursor)
            meta_id = self._get_label_id(meta_name)
            cursor.execute(
                "INSERT INTO Relations (src_id, target_id, relation_id) VALUES (?, ?, ?)",
                (self.id, value_id, self._get_relation_id("meta_of"))
            )
            db_connection.commit()
            if should_close:
                db_connection.close()
            return True
        except Exception as e:
            db_connection.rollback()
            if should_close:
                db_connection.close()
            raise e

    def get_type(self, db_connection: Optional[sqlite3.Connection] = None) -> str:
        should_close = False
        if db_connection is None:
            db_connection = sqlite3.connect("database.db")
            should_close = True
        cursor = db_connection.cursor()
        try:
            cursor.execute(
                """
                SELECT l.label 
                FROM Relations r
                JOIN Labels l ON r.target_id = l.id
                WHERE r.src_id = ? AND r.relation_id = ?
                """,
                (self.id, self._get_relation_id("type_of"))
            )
            result = cursor.fetchone()
            if should_close:
                db_connection.close()
            return result[0] if result else self.TYPE_NAME
        except Exception as e:
            if should_close:
                db_connection.close()
            raise e

    def to_dict(self) -> Dict[str, Any]:
        result = {
            "id": self.id,
            "type": self.type_name,
        }
        metas = self.get_metas()
        result.update(metas)
        return result

    def debug(self) -> str:
        return json.dumps(self.to_dict(), indent=2)

    @staticmethod
    def _get_label_id(label_text: str, cursor: Optional[sqlite3.Cursor] = None) -> int:
        should_close = False
        conn = None
        if cursor is None:
            conn = sqlite3.connect("database.db")
            cursor = conn.cursor()
            should_close = True
        try:
            cursor.execute("SELECT id FROM Labels WHERE label = ?", (label_text,))
            result = cursor.fetchone()
            if result:
                label_id = result[0]
            else:
                cursor.execute("INSERT INTO Labels (label) VALUES (?)", (label_text,))
                label_id = cursor.lastrowid
                if conn:
                    conn.commit()
            if should_close and conn:
                conn.close()
            return label_id
        except Exception as e:
            if conn:
                conn.rollback()
            if should_close and conn:
                conn.close()
            raise e

    @staticmethod
    def _get_relation_id(relation_name: str) -> int:
        conn = sqlite3.connect("database.db")
        cursor = conn.cursor()
        try:
            cursor.execute("SELECT id FROM Labels WHERE label = ?", (relation_name,))
            result = cursor.fetchone()
            conn.close()
            if result:
                return result[0]
            else:
                raise ValueError(f"Relation '{relation_name}' non trouvée dans la base de données")
        except Exception as e:
            conn.close()
            raise e

    @staticmethod
    def _save_value_as_label(value: Any, cursor: sqlite3.Cursor) -> int:
        if isinstance(value, (dict, list)):
            value_text = json.dumps(value, ensure_ascii=False)
        else:
            value_text = str(value)
        cursor.execute("SELECT id FROM Labels WHERE label = ?", (value_text,))
        result = cursor.fetchone()
        if result:
            return result[0]
        else:
            cursor.execute("INSERT INTO Labels (label) VALUES (?)", (value_text,))
            return cursor.lastrowid

